## Proposed Structure

```
.opencode/
├── lib/
│   └── session-export.ts      # Shared export logic
└── tools/
    ├── export-session.ts      # Uses lib
    └── git-commit.ts          # Uses lib
```

### `.opencode/lib/session-export.ts`

```typescript
import path from "path"
import { $ } from "bun"

// Types
export type ToolInput = Record<string, unknown> | string | number | boolean | null

export type FilteredMessage = {
  role?: string
  content?: string
  tools_used?: Array<{
    tool?: string
    input?: ToolInput
    output?: string
    status?: string
    sessionId?: string
  }>
}

export type FilteredSession = {
  sessionID?: string
  messages: FilteredMessage[]
}

// Constants
const SKIP_OUTPUT_TOOLS = ["webfetch"]
const DEFAULT_OUTPUT_MAX_CHARS = 10000
const OUTPUT_MAX_CHARS: Record<string, number> = {
  bash: 1000,
  grep: 4000,
}

// Main export function
export async function exportSession(
  sessionID: string,
  outputPath: string,
  options?: { deleteRaw?: boolean }
): Promise<string> {
  const rawPath = `${outputPath}.raw.json`

  await $`sh -c ${`opencode export ${sessionID} > ${rawPath}`}`

  const rawJson = JSON.parse(await Bun.file(rawPath).text())
  const filtered = filterSession(rawJson)
  await Bun.write(outputPath, JSON.stringify(filtered, null, 2))

  if (options?.deleteRaw !== false) {
    await Bun.file(rawPath).unlink()
  }

  return outputPath
}

// Filtering functions
export function filterSession(raw: unknown): FilteredSession { ... }
function filterMessage(message: unknown): FilteredMessage { ... }
function isToolPart(part: unknown): part is Record<string, unknown> { ... }
function normalizeToolPart(part: Record<string, unknown>): { ... } { ... }
```

### `.opencode/tools/export-session.ts` (simplified)

```typescript
import path from "path"
import { tool } from "@opencode-ai/plugin"
import { exportSession } from "../lib/session-export"

export default tool({
  description: "Export current session to filtered JSON file",
  args: {
    outputPath: tool.schema.string().describe("Path to save session JSON"),
    deleteRaw: tool.schema.boolean().default(true),
  },
  async execute(args, context) {
    const { sessionID, worktree } = context
    const baseDir = worktree ?? process.cwd()
    const outputPath = path.isAbsolute(args.outputPath)
      ? args.outputPath
      : path.join(baseDir, args.outputPath)

    await exportSession(sessionID, outputPath, { deleteRaw: args.deleteRaw })
    return `Exported session ${sessionID} to ${outputPath}`
  },
})
```

### `.opencode/tools/git-commit.ts` (uses lib)

```typescript
import path from "path"
import { tool } from "@opencode-ai/plugin"
import { $ } from "bun"
import { exportSession } from "../lib/session-export"

export default tool({
  // ... description and args
  async execute(args, context) {
    const { sessionID, agent, worktree } = context

    // 1. Export session
    const sessionDir = path.join(worktree ?? process.cwd(), "aivocode/sessions", sessionID)
    const exportPath = path.join(sessionDir, `${sessionID}.json`)
    await exportSession(sessionID, exportPath)

    // 2. Build trailer args
    const allTrailers = { "Session-ID": sessionID, ...args.trailers }
    const trailerArgs = Object.entries(allTrailers)
      .map(([k, v]) => `--trailer "${k}: ${v}"`)
      .join(" ")

    // 3. Stage and commit
    const files = [...args.files, exportPath]
    await $`git add ${files.join(" ")}`
    await $`git commit --author="opencode/${agent} <noreply@opencode.ai>" --message="${args.message}" ${trailerArgs}`

    return `Committed with Session-ID: ${sessionID}`
  },
})
```

